import { expectDiagnostics } from "@typespec/compiler/testing";
import { describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";

describe("@assumption", () => {
  // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_assumption
  describe("valid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T012.T012_01
    it("on a @product namespace", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @product
        @assumption(#{
          id: "A01",
          assumption: "GitHub API is available 99.9% of the time",
          source: "https://www.githubstatus.com/"
        })
        namespace Products.MyProduct;
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T012.T012_04
    it("on a @feature namespace", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @feature
        @assumption(#{
          id: "A02",
          assumption: "LLM latency stays under 30s per call",
          source: "https://platform.openai.com/docs/guides/rate-limits"
        })
        namespace Products.MyProduct.Features.MyFeature;
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T012.T012_02
    it("on a @dependency namespace", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @dependency(#{
          title: "GitHub Dep",
          type: DependencyType.Service,
          status: DependencyStatus.Active,
          sources: #[#{ url: "https://docs.github.com", description: "GitHub REST API docs" }]
        })
        @assumption(#{
          id: "A03",
          assumption: "Webhook delivery order is not guaranteed",
          source: "https://docs.github.com/en/developers/webhooks-and-events"
        })
        namespace Dependencies.GithubDep;
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T012.T012_05
    it("multiple assumptions on same namespace", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @product
        @assumption(#{
          id: "A01",
          assumption: "GitHub API is available",
          source: "https://www.githubstatus.com/"
        })
        @assumption(#{
          id: "A02",
          assumption: "Users have valid GitHub tokens",
          source: "https://docs.github.com/en/authentication"
        })
        namespace Products.MyProduct;
      `);
    });
  });

  describe("invalid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T012.T012_03
    it("on a bare namespace with no structural decorator", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @assumption(#{
          id: "A01",
          assumption: "Something is true",
          source: "https://example.com"
        })
        namespace SomeRandomNamespace;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-assumption-context",
        message: /SomeRandomNamespace/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T012.T012_06
    it("on a @component namespace — not allowed", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{
          type: ComponentType.Agent,
        })
        @assumption(#{
          id: "A01",
          assumption: "Something is true",
          source: "https://example.com"
        })
        namespace Components.MyAgent;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-assumption-context",
        message: /Components\.MyAgent/,
      });
    });

  });
});
